// CLX Stripe Webhook v1 — Verify signature (TASK 3)
// Stripe signs every webhook body with HMAC-SHA256 using the endpoint
// signing secret. We reproduce that verification here so we don't
// process forged events. The signature format is:
//   Stripe-Signature: t=<timestamp>,v1=<sig>,v1=<sig>...
// Verification: HMAC_SHA256(secret, `${t}.${raw_body}`) == v1
//
// On verification failure we log STRIPE_WEBHOOK_UNVERIFIED to
// scan_errors and short-circuit; no downstream nodes fire.

const crypto = require('crypto');

const headers = $input.item.json.headers || {};
const rawBody = $input.item.json.body || $input.item.binary && $input.item.binary.body && $input.item.binary.body.data;

const sigHeader = headers['stripe-signature'] || headers['Stripe-Signature'] || '';
const secret = process.env.STRIPE_WEBHOOK_SECRET || 'TODO_STRIPE_WEBHOOK_SECRET';

let verified = false;
let timestamp = null;
let v1 = null;
let payload = null;
let eventId = null;
let eventType = null;

try {
  const parts = String(sigHeader).split(',').map(function(p) { return p.trim(); });
  for (const p of parts) {
    if (p.startsWith('t=')) timestamp = p.slice(2);
    else if (p.startsWith('v1=')) v1 = p.slice(3);
  }

  const bodyString = typeof rawBody === 'string' ? rawBody : JSON.stringify($input.item.json.body || {});

  if (timestamp && v1 && secret !== 'TODO_STRIPE_WEBHOOK_SECRET') {
    const signedPayload = timestamp + '.' + bodyString;
    const expected = crypto.createHmac('sha256', secret).update(signedPayload).digest('hex');
    // timing-safe compare
    if (expected.length === v1.length && crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(v1))) {
      verified = true;
    }
  }

  payload = typeof rawBody === 'string' ? JSON.parse(rawBody) : ($input.item.json.body || {});
  eventId = payload.id || null;
  eventType = payload.type || null;
} catch (e) {
  return { json: { _verify_failed: true, verify_error: e.message || 'parse failure' } };
}

if (!verified) {
  return { json: { _verify_failed: true, event_id: eventId, event_type: eventType, payload } };
}

return { json: { event_id: eventId, event_type: eventType, payload, verified: true } };

// CLX Stripe Webhook v1 — Dispatch event type (TASK 3)
// Routes each handled event type to the correct downstream branch.
// Unhandled event types fall through as a no-op (logged to
// stripe_events_log above and marked processed=true for housekeeping).
//
// Handled types:
//   customer.subscription.created  -> upsert clients row with sub id + status
//   customer.subscription.updated  -> update status + next_billing_date
//   customer.subscription.deleted  -> mark canceled
//   invoice.paid                   -> record last_payment + next_billing
//   invoice.payment_failed         -> scan_errors STRIPE_PAYMENT_FAILED

const data = $('Verify Signature').first().json;
const payload = data.payload || {};
const event_type = data.event_type || '';
const obj = (payload.data && payload.data.object) || {};

const stripe_customer_id = obj.customer || null;
const stripe_subscription_id = (event_type.startsWith('customer.subscription.') ? obj.id : obj.subscription) || null;
const status = obj.status || null;
const current_period_end = obj.current_period_end ? new Date(obj.current_period_end * 1000).toISOString() : null;
const next_billing_date = current_period_end ? current_period_end.slice(0, 10) : null;
const trial_end = obj.trial_end ? new Date(obj.trial_end * 1000).toISOString() : null;
const amount_paid = obj.amount_paid ? Number(obj.amount_paid) / 100 : null;
const paid_at = obj.status_transitions && obj.status_transitions.paid_at
  ? new Date(obj.status_transitions.paid_at * 1000).toISOString()
  : (event_type === 'invoice.paid' ? new Date().toISOString() : null);
const customer_email = (obj.customer_email) || (obj.receipt_email) || null;

return {
  json: {
    event_id: data.event_id,
    event_type,
    stripe_customer_id,
    stripe_subscription_id,
    status,
    next_billing_date,
    trial_end,
    amount_paid,
    paid_at,
    customer_email,
    is_subscription_created:  event_type === 'customer.subscription.created',
    is_subscription_updated:  event_type === 'customer.subscription.updated',
    is_subscription_deleted:  event_type === 'customer.subscription.deleted',
    is_invoice_paid:          event_type === 'invoice.paid' || event_type === 'invoice.payment_succeeded',
    is_payment_failed:        event_type === 'invoice.payment_failed',
    raw: obj
  }
};
